const inputData = $input.first().json;

// Handle network/connection errors from Fetch Target URL
if (inputData.error) {
  const url = $('Webhook').first().json.body.url;
  return [{
    json: {
      url,
      error: true,
      errorMessage: 'Could not connect to ' + url + '. The site may be unreachable, blocking automated requests, or the URL may be invalid.',
      score: null,
      maxScore: 100,
      grade: null,
      scannedAt: new Date().toISOString(),
      summary: { total: 0, passing: 0, failing: 0 },
      headers: []
    }
  }];
}

const headers = inputData.headers || {};
const url = $('Webhook').first().json.body.url;

const SECURITY_HEADERS = {
  'content-security-policy': {
    name: 'Content-Security-Policy',
    weight: 30,
    description: 'Prevents XSS and code injection attacks',
    fix: "Add: Content-Security-Policy: default-src 'self'"
  },
  'strict-transport-security': {
    name: 'Strict-Transport-Security (HSTS)',
    weight: 20,
    description: 'Forces HTTPS connections, prevents downgrade attacks',
    fix: 'Add: Strict-Transport-Security: max-age=31536000; includeSubDomains'
  },
  'x-frame-options': {
    name: 'X-Frame-Options',
    weight: 15,
    description: 'Prevents clickjacking by blocking iframe embedding',
    fix: 'Add: X-Frame-Options: DENY'
  },
  'x-content-type-options': {
    name: 'X-Content-Type-Options',
    weight: 15,
    description: 'Prevents MIME-type sniffing attacks',
    fix: 'Add: X-Content-Type-Options: nosniff'
  },
  'referrer-policy': {
    name: 'Referrer-Policy',
    weight: 10,
    description: 'Controls how much referrer info is shared',
    fix: 'Add: Referrer-Policy: strict-origin-when-cross-origin'
  },
  'permissions-policy': {
    name: 'Permissions-Policy',
    weight: 10,
    description: 'Controls access to browser APIs (camera, mic, GPS)',
    fix: 'Add: Permissions-Policy: geolocation=(), microphone=(), camera=()'
  }
};

const results = [];
let totalScore = 0;
const missing = [];
const present = [];

for (const [key, config] of Object.entries(SECURITY_HEADERS)) {
  const value = headers[key] || null;
  const isPresent = value !== null;
  if (isPresent) {
    totalScore += config.weight;
    present.push(config.name);
  } else {
    missing.push(config.name);
  }
  results.push({
    header: config.name,
    key,
    present: isPresent,
    value: value || null,
    weight: config.weight,
    description: config.description,
    fix: isPresent ? null : config.fix
  });
}

const grade = totalScore >= 90 ? 'A+' : totalScore >= 80 ? 'A' : totalScore >= 70 ? 'B' : totalScore >= 55 ? 'C' : totalScore >= 40 ? 'D' : 'F';

return [{
  json: {
    url,
    score: totalScore,
    maxScore: 100,
    grade,
    scannedAt: new Date().toISOString(),
    summary: {
      total: results.length,
      passing: present.length,
      failing: missing.length
    },
    headers: results
  }
}];
